@Override
public boolean epsilonEquals(final Vector3 other, float epsilon) {
    if (other == null)
        return false;
    if (Math.abs(other.x - x) > epsilon)
        return false;
    if (Math.abs(other.y - y) > epsilon)
        return false;
    if (Math.abs(other.z - z) > epsilon)
        return false;
    return true;
}
